import { createClient, generateCmekKey, cmekEncrypt, cmekDecrypt, cmekFingerprint, toBase64 } from "@1claw/sdk";

const client = createClient({
  baseUrl: "https://api.1claw.xyz",
  apiKey: process.env.ONECLAW_API_KEY!,
});

const vaultId = process.env.ONECLAW_VAULT_ID!;

async function main() {
  const key = await generateCmekKey();
  console.log("fingerprint:", cmekFingerprint(key));

  const blob = cmekEncrypt(key, "sk-live-secret-value");
  await client.secrets.put(vaultId, "api-keys/stripe", {
    type: "api_key",
    value: toBase64(blob),
  });

  const res = await client.secrets.get(vaultId, "api-keys/stripe");
  if (res.data) {
    const plaintext = cmekDecrypt(key, res.data.value);
    console.log("decrypted:", plaintext);
  }
}
main();
